SELECT count(*) FROM movie_info, title, info_type, movie_companies, company_name, company_type, cast_info, name WHERE movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id;